using ArchStudy.Clean.Entities;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Clean.Adapters.Persistence;

public class CleanDbContext(DbContextOptions<CleanDbContext> options) : DbContext(options)
{
    public DbSet<Account> Accounts => Set<Account>();
    public DbSet<Transaction> Transactions => Set<Transaction>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Account>(b =>
        {
            b.HasKey(a => a.Id);
            b.Property(a => a.Owner).IsRequired();
        });

        modelBuilder.Entity<Transaction>(b => b.HasKey(t => t.Id));
    }
}

using ArchStudy.Clean.Entities;
using ArchStudy.Clean.UseCases.Common;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Clean.Adapters.Persistence;

public class EfAccountGateway(CleanDbContext db) : IAccountGateway
{
    public Task<Account?> FindAsync(Guid id, CancellationToken ct) =>
        db.Accounts.FirstOrDefaultAsync(a => a.Id == id, ct);

    public async Task SaveAsync(Account account, CancellationToken ct)
    {
        if (db.Entry(account).State == EntityState.Detached)
            await db.Accounts.AddAsync(account, ct);
    }
}

public class EfTransactionGateway(CleanDbContext db) : ITransactionGateway
{
    public async Task<IReadOnlyList<Transaction>> ListAsync(Guid accountId, CancellationToken ct) =>
        await db.Transactions
            .Where(t => t.AccountId == accountId)
            .OrderByDescending(t => t.Timestamp)
            .ToListAsync(ct);

    public async Task RecordAsync(Transaction transaction, CancellationToken ct) =>
        await db.Transactions.AddAsync(transaction, ct);
}

public class EfPersistenceContext(CleanDbContext db) : IPersistenceContext
{
    public Task CommitAsync(CancellationToken ct) => db.SaveChangesAsync(ct);
}

using ArchStudy.Clean.Adapters.Persistence;
using ArchStudy.Clean.Frameworks.Web;
using ArchStudy.Clean.UseCases;
using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;
using Microsoft.EntityFrameworkCore;

namespace ArchStudy.Clean;

public static class CleanModule
{
    public static IServiceCollection AddCleanModule(this IServiceCollection services)
    {
        services.AddDbContext<CleanDbContext>(o => o.UseSqlite("Data Source=archstudy-clean.db"));
        services.AddScoped<IAccountGateway, EfAccountGateway>();
        services.AddScoped<ITransactionGateway, EfTransactionGateway>();
        services.AddScoped<IPersistenceContext, EfPersistenceContext>();

        services.AddScoped<IRequestHandler<CreateAccountInput, UseCaseResult<AccountResponse>>, CreateAccountUseCase>();
        services.AddScoped<IRequestHandler<GetAccountInput, UseCaseResult<AccountResponse>>, GetAccountUseCase>();
        services.AddScoped<IRequestHandler<GetStatementInput, UseCaseResult<IReadOnlyList<TransactionResponse>>>, GetStatementUseCase>();
        services.AddScoped<IRequestHandler<DepositInput, UseCaseResult<AccountResponse>>, DepositUseCase>();
        services.AddScoped<IRequestHandler<WithdrawInput, UseCaseResult<AccountResponse>>, WithdrawUseCase>();
        services.AddScoped<IRequestHandler<TransferInput, UseCaseResult<Unit>>, TransferUseCase>();
        return services;
    }

    public static IEndpointRouteBuilder MapCleanModule(this IEndpointRouteBuilder routes)
    {
        var group = routes.MapGroup("/clean").WithTags("Clean");
        CleanEndpoints.Map(group);
        return routes;
    }

    public static async Task EnsureDatabaseCreatedAsync(IServiceProvider services)
    {
        var db = services.GetRequiredService<CleanDbContext>();
        await db.Database.EnsureCreatedAsync();
    }
}

namespace ArchStudy.Clean.Entities;

public class Account
{
    public Guid Id { get; private set; }
    public string Owner { get; private set; } = string.Empty;
    public decimal Balance { get; private set; }
    public DateTime CreatedAt { get; private set; }

    private Account() { }

    public static Account Open(string owner, DateTime now) =>
        new() { Id = Guid.NewGuid(), Owner = owner, Balance = 0m, CreatedAt = now };

    public bool TryDeposit(decimal amount)
    {
        if (amount <= 0) return false;
        Balance += amount;
        return true;
    }

    public bool TryWithdraw(decimal amount)
    {
        if (amount <= 0 || Balance < amount) return false;
        Balance -= amount;
        return true;
    }
}

using ArchStudy.Shared.Dtos;

namespace ArchStudy.Clean.Entities;

public class Transaction
{
    public Guid Id { get; private set; }
    public Guid AccountId { get; private set; }
    public TransactionType Type { get; private set; }
    public decimal Amount { get; private set; }
    public DateTime Timestamp { get; private set; }
    public Guid? RelatedAccountId { get; private set; }

    private Transaction() { }

    public static Transaction Create(Guid accountId, TransactionType type, decimal amount, DateTime now, Guid? related = null) =>
        new()
        {
            Id = Guid.NewGuid(),
            AccountId = accountId,
            Type = type,
            Amount = amount,
            Timestamp = now,
            RelatedAccountId = related,
        };
}

using ArchStudy.Clean.UseCases;
using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Clean.Frameworks.Web;

public static class CleanEndpoints
{
    public static void Map(RouteGroupBuilder group)
    {
        group.MapPost("/accounts", async Task<IResult> (
            CreateAccountRequest req,
            IRequestHandler<CreateAccountInput, UseCaseResult<AccountResponse>> handler,
            CancellationToken ct) =>
            ToHttp(await handler.Handle(new CreateAccountInput(req.Owner), ct),
                a => Results.Created($"/clean/accounts/{a.Id}", a)));

        group.MapGet("/accounts/{id:guid}", async Task<IResult> (
            Guid id,
            IRequestHandler<GetAccountInput, UseCaseResult<AccountResponse>> handler,
            CancellationToken ct) =>
            ToHttp(await handler.Handle(new GetAccountInput(id), ct), Results.Ok));

        group.MapGet("/accounts/{id:guid}/transactions", async Task<IResult> (
            Guid id,
            IRequestHandler<GetStatementInput, UseCaseResult<IReadOnlyList<TransactionResponse>>> handler,
            CancellationToken ct) =>
            ToHttp(await handler.Handle(new GetStatementInput(id), ct), Results.Ok));

        group.MapPost("/accounts/{id:guid}/deposits", async Task<IResult> (
            Guid id,
            DepositRequest req,
            IRequestHandler<DepositInput, UseCaseResult<AccountResponse>> handler,
            CancellationToken ct) =>
            ToHttp(await handler.Handle(new DepositInput(id, req.Amount), ct), Results.Ok));

        group.MapPost("/accounts/{id:guid}/withdrawals", async Task<IResult> (
            Guid id,
            WithdrawalRequest req,
            IRequestHandler<WithdrawInput, UseCaseResult<AccountResponse>> handler,
            CancellationToken ct) =>
            ToHttp(await handler.Handle(new WithdrawInput(id, req.Amount), ct), Results.Ok));

        group.MapPost("/transfers", async Task<IResult> (
            TransferRequest req,
            IRequestHandler<TransferInput, UseCaseResult<Unit>> handler,
            CancellationToken ct) =>
            ToHttp(await handler.Handle(new TransferInput(req.FromAccountId, req.ToAccountId, req.Amount), ct),
                _ => Results.NoContent()));
    }

    private static IResult ToHttp<T>(UseCaseResult<T> result, Func<T, IResult> onSuccess) => result switch
    {
        UseCaseResult<T>.Ok ok => onSuccess(ok.Value),
        UseCaseResult<T>.NotFound nf => Results.NotFound(new { error = nf.Message }),
        UseCaseResult<T>.Invalid inv => Results.BadRequest(new { error = inv.Message }),
        _ => Results.StatusCode(500),
    };
}

using ArchStudy.Clean.Entities;

namespace ArchStudy.Clean.UseCases.Common;

public interface IAccountGateway
{
    Task<Account?> FindAsync(Guid id, CancellationToken ct);
    Task SaveAsync(Account account, CancellationToken ct);
}

public interface ITransactionGateway
{
    Task<IReadOnlyList<Transaction>> ListAsync(Guid accountId, CancellationToken ct);
    Task RecordAsync(Transaction transaction, CancellationToken ct);
}

public interface IPersistenceContext
{
    Task CommitAsync(CancellationToken ct);
}

namespace ArchStudy.Clean.UseCases.Common;

public abstract record UseCaseResult<T>
{
    public sealed record Ok(T Value) : UseCaseResult<T>;
    public sealed record NotFound(string Message) : UseCaseResult<T>;
    public sealed record Invalid(string Message) : UseCaseResult<T>;
}

using ArchStudy.Clean.Entities;
using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Clean.UseCases;

public sealed record CreateAccountInput(string Owner) : IRequest<UseCaseResult<AccountResponse>>;

public sealed class CreateAccountUseCase(
    IAccountGateway accounts,
    IPersistenceContext context)
    : IRequestHandler<CreateAccountInput, UseCaseResult<AccountResponse>>
{
    public async ValueTask<UseCaseResult<AccountResponse>> Handle(CreateAccountInput input, CancellationToken ct)
    {
        if (string.IsNullOrWhiteSpace(input.Owner))
            return new UseCaseResult<AccountResponse>.Invalid("Owner is required");

        var account = Account.Open(input.Owner, DateTime.UtcNow);
        await accounts.SaveAsync(account, ct);
        await context.CommitAsync(ct);

        return new UseCaseResult<AccountResponse>.Ok(
            new AccountResponse(account.Id, account.Owner, account.Balance, account.CreatedAt));
    }
}

using ArchStudy.Clean.Entities;
using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Clean.UseCases;

public sealed record DepositInput(Guid AccountId, decimal Amount) : IRequest<UseCaseResult<AccountResponse>>;

public sealed class DepositUseCase(
    IAccountGateway accounts,
    ITransactionGateway transactions,
    IPersistenceContext context)
    : IRequestHandler<DepositInput, UseCaseResult<AccountResponse>>
{
    public async ValueTask<UseCaseResult<AccountResponse>> Handle(DepositInput input, CancellationToken ct)
    {
        if (input.Amount <= 0) return new UseCaseResult<AccountResponse>.Invalid("Amount must be positive");

        var account = await accounts.FindAsync(input.AccountId, ct);
        if (account is null) return new UseCaseResult<AccountResponse>.NotFound("Account not found");

        if (!account.TryDeposit(input.Amount))
            return new UseCaseResult<AccountResponse>.Invalid("Invalid deposit");

        await transactions.RecordAsync(Transaction.Create(account.Id, TransactionType.Deposit, input.Amount, DateTime.UtcNow), ct);
        await context.CommitAsync(ct);

        return new UseCaseResult<AccountResponse>.Ok(new AccountResponse(account.Id, account.Owner, account.Balance, account.CreatedAt));
    }
}

using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Clean.UseCases;

public sealed record GetAccountInput(Guid Id) : IRequest<UseCaseResult<AccountResponse>>;

public sealed class GetAccountUseCase(IAccountGateway accounts)
    : IRequestHandler<GetAccountInput, UseCaseResult<AccountResponse>>
{
    public async ValueTask<UseCaseResult<AccountResponse>> Handle(GetAccountInput input, CancellationToken ct)
    {
        var account = await accounts.FindAsync(input.Id, ct);
        return account is null
            ? new UseCaseResult<AccountResponse>.NotFound("Account not found")
            : new UseCaseResult<AccountResponse>.Ok(new AccountResponse(account.Id, account.Owner, account.Balance, account.CreatedAt));
    }
}

using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Clean.UseCases;

public sealed record GetStatementInput(Guid AccountId) : IRequest<UseCaseResult<IReadOnlyList<TransactionResponse>>>;

public sealed class GetStatementUseCase(ITransactionGateway transactions)
    : IRequestHandler<GetStatementInput, UseCaseResult<IReadOnlyList<TransactionResponse>>>
{
    public async ValueTask<UseCaseResult<IReadOnlyList<TransactionResponse>>> Handle(GetStatementInput input, CancellationToken ct)
    {
        var rows = await transactions.ListAsync(input.AccountId, ct);
        IReadOnlyList<TransactionResponse> mapped = rows
            .Select(t => new TransactionResponse(t.Id, t.AccountId, t.Type, t.Amount, t.Timestamp, t.RelatedAccountId))
            .ToList();
        return new UseCaseResult<IReadOnlyList<TransactionResponse>>.Ok(mapped);
    }
}

using ArchStudy.Clean.Entities;
using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Clean.UseCases;

public sealed record TransferInput(Guid FromAccountId, Guid ToAccountId, decimal Amount) : IRequest<UseCaseResult<Unit>>;

public sealed class TransferUseCase(
    IAccountGateway accounts,
    ITransactionGateway transactions,
    IPersistenceContext context)
    : IRequestHandler<TransferInput, UseCaseResult<Unit>>
{
    public async ValueTask<UseCaseResult<Unit>> Handle(TransferInput input, CancellationToken ct)
    {
        if (input.Amount <= 0) return new UseCaseResult<Unit>.Invalid("Amount must be positive");
        if (input.FromAccountId == input.ToAccountId) return new UseCaseResult<Unit>.Invalid("Accounts must differ");

        var from = await accounts.FindAsync(input.FromAccountId, ct);
        if (from is null) return new UseCaseResult<Unit>.NotFound("Source account not found");
        var to = await accounts.FindAsync(input.ToAccountId, ct);
        if (to is null) return new UseCaseResult<Unit>.NotFound("Destination account not found");

        if (!from.TryWithdraw(input.Amount)) return new UseCaseResult<Unit>.Invalid("Insufficient funds");
        to.TryDeposit(input.Amount);

        var now = DateTime.UtcNow;
        await transactions.RecordAsync(Transaction.Create(from.Id, TransactionType.TransferOut, input.Amount, now, to.Id), ct);
        await transactions.RecordAsync(Transaction.Create(to.Id, TransactionType.TransferIn, input.Amount, now, from.Id), ct);
        await context.CommitAsync(ct);

        return new UseCaseResult<Unit>.Ok(Unit.Value);
    }
}

using ArchStudy.Clean.Entities;
using ArchStudy.Clean.UseCases.Common;
using ArchStudy.Shared.Dtos;
using Mediator;

namespace ArchStudy.Clean.UseCases;

public sealed record WithdrawInput(Guid AccountId, decimal Amount) : IRequest<UseCaseResult<AccountResponse>>;

public sealed class WithdrawUseCase(
    IAccountGateway accounts,
    ITransactionGateway transactions,
    IPersistenceContext context)
    : IRequestHandler<WithdrawInput, UseCaseResult<AccountResponse>>
{
    public async ValueTask<UseCaseResult<AccountResponse>> Handle(WithdrawInput input, CancellationToken ct)
    {
        if (input.Amount <= 0) return new UseCaseResult<AccountResponse>.Invalid("Amount must be positive");

        var account = await accounts.FindAsync(input.AccountId, ct);
        if (account is null) return new UseCaseResult<AccountResponse>.NotFound("Account not found");

        if (!account.TryWithdraw(input.Amount))
            return new UseCaseResult<AccountResponse>.Invalid("Insufficient funds");

        await transactions.RecordAsync(Transaction.Create(account.Id, TransactionType.Withdrawal, input.Amount, DateTime.UtcNow), ct);
        await context.CommitAsync(ct);

        return new UseCaseResult<AccountResponse>.Ok(new AccountResponse(account.Id, account.Owner, account.Balance, account.CreatedAt));
    }
}
